// Service worker for Propwash. Generated by build.mjs — do not edit out/sw.js directly.
//
// Strategy:
//   - Precache the app shell (HTML, JS, CSS, WASM, vendor scripts) on install.
//   - Navigation requests: network-first with cache fallback. Lets users get the
//     latest index.html when online without breaking offline use.
//   - Same-origin GETs: cache-first. All non-HTML assets are content-hashed, so
//     a cached copy is always correct for its URL.
//   - No skipWaiting / clients.claim. A new SW takes over only when the user
//     closes every tab — avoids reloading mid-analysis.

const VERSION = "__VERSION__";
const CACHE = `propwash-${VERSION}`;
const PRECACHE = __PRECACHE__;

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(CACHE).then((cache) => cache.addAll(PRECACHE)),
  );
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(
        keys
          .filter((k) => k.startsWith("propwash-") && k !== CACHE)
          .map((k) => caches.delete(k)),
      ),
    ),
  );
});

self.addEventListener("fetch", (event) => {
  const req = event.request;
  if (req.method !== "GET") return;

  const url = new URL(req.url);
  if (url.origin !== self.location.origin) return;

  if (req.mode === "navigate") {
    event.respondWith(networkFirst(req));
    return;
  }

  event.respondWith(cacheFirst(req));
});

async function networkFirst(req) {
  const cache = await caches.open(CACHE);
  try {
    const fresh = await fetch(req);
    if (fresh.ok) cache.put(req, fresh.clone());
    return fresh;
  } catch (_) {
    const cached = await cache.match(req) || await cache.match("./index.html");
    if (cached) return cached;
    throw _;
  }
}

async function cacheFirst(req) {
  const cache = await caches.open(CACHE);
  const cached = await cache.match(req);
  if (cached) return cached;
  const fresh = await fetch(req);
  if (fresh.ok) cache.put(req, fresh.clone());
  return fresh;
}
